#ifdef cl_khr_fp64
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    int tx = get_local_id(0);

    if (tx == 0) {
        int i, j, k;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                shadow[i * BLOCK_SIZE + j] =
                    m[(offset + i) * matrix_dim + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = shadow[i * BLOCK_SIZE + j];
                for (k = 0; k < i; k++) {
                    sum -= shadow[i * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + j];
                }
                shadow[i * BLOCK_SIZE + j] = sum;
            }

            for (j = i + 1; j < BLOCK_SIZE; j++) {
                float sum = shadow[j * BLOCK_SIZE + i];
                for (k = 0; k < i; k++) {
                    sum -= shadow[j * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + i];
                }
                shadow[j * BLOCK_SIZE + i] = sum / shadow[i * BLOCK_SIZE + i];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + i) * matrix_dim + (offset + j)] =
                    shadow[i * BLOCK_SIZE + j];
            }
        }
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    int tx = get_local_id(0);
    int chunk = get_group_id(0);

    if (tx < BLOCK_SIZE) {
        int j;
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[tx * BLOCK_SIZE + j] =
                m[(offset + tx) * matrix_dim + (offset + j)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx == 0) {
        int i, j, k;
        int i_global = offset;
        int j_global = offset + BLOCK_SIZE * (chunk + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += dia[i * BLOCK_SIZE + k] *
                           m[(i_global + k) * matrix_dim + (j_global + j)];
                }
                m[(i_global + i) * matrix_dim + (j_global + j)] -= sum;
            }
        }
    }

    if (tx == BLOCK_SIZE) {
        int i, j, k;
        int i_global = offset + BLOCK_SIZE * (chunk + 1);
        int j_global = offset;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += m[(i_global + i) * matrix_dim + (j_global + k)] *
                           dia[k * BLOCK_SIZE + j];
                }
                m[(i_global + i) * matrix_dim + (j_global + j)] =
                    (m[(i_global + i) * matrix_dim + (j_global + j)] - sum) /
                    m[(offset + j) * matrix_dim + (offset + j)];
            }
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int i_global = offset + BLOCK_SIZE * (1 + by);
    int j_global = offset + BLOCK_SIZE * (1 + bx);

    peri_row[ty * BLOCK_SIZE + tx] =
        m[(offset + ty) * matrix_dim + (j_global + tx)];
    peri_col[ty * BLOCK_SIZE + tx] =
        m[(i_global + ty) * matrix_dim + (offset + tx)];

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += peri_col[ty * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
    }

    m[(i_global + ty) * matrix_dim + (j_global + tx)] -= sum;
}
